import { LeavePolicy } from "./policy.model";
import { ILeavePolicyRepository } from "./policy.repository";
import { CreateLeaveRequestDto } from "../leave/leave.model";
import { AuditLogService } from "../../shared/audit/audit.service";
import { ValidationResult } from "../../shared/types/validation.types";

export interface ILeavePolicyService {
  getActivePolicies(): Promise<LeavePolicy[]>;
  getPolicyById(id: string): Promise<LeavePolicy | null>;
  getPolicyByLeaveType(leaveType: string): Promise<LeavePolicy | null>;
  validateLeaveRequestAgainstPolicy(request: CreateLeaveRequestDto): Promise<ValidationResult>;
}

export class LeavePolicyService implements ILeavePolicyService {
  constructor(
    private readonly policyRepository: ILeavePolicyRepository,
    private readonly auditLogService: AuditLogService
  ) {}

  async getActivePolicies(): Promise<LeavePolicy[]> {
    return this.policyRepository.findActive();
  }

  async getPolicyById(id: string): Promise<LeavePolicy | null> {
    return this.policyRepository.findById(id);
  }

  async getPolicyByLeaveType(leaveType: string): Promise<LeavePolicy | null> {
    return this.policyRepository.findByLeaveType(leaveType);
  }

  async validateLeaveRequestAgainstPolicy(request: CreateLeaveRequestDto): Promise<ValidationResult> {
    const errors: string[] = [];
    const policy = await this.policyRepository.findById(request.policyId);

    if (!policy) {
      errors.push(`Policy with ID ${request.policyId} not found`);
      return { isValid: false, errors };
    }

    if (!policy.isActive) {
      errors.push(`Policy ${policy.policyName} is not active`);
    }

    if (policy.advanceNoticeDays > 0) {
      const noticeDays = Math.floor((request.startDate.getTime() - new Date().getTime()) / (1000 * 60 * 60 * 24));
      if (noticeDays < policy.advanceNoticeDays) {
        errors.push(`Requires ${policy.advanceNoticeDays} days advance notice, only ${noticeDays} days given`);
      }
    }

    return {
      isValid: errors.length === 0,
      errors
    };
  }
}","File: src/modules/balance/balance.service.ts
