import { ValidationResult } from "../../shared/types/validation.types";

export interface ILeaveBalanceService {
  getEmployeeBalance(employeeId: string, policyId: string, year: number): Promise<LeaveBalance | null>;
  getEmployeeBalancesForYear(employeeId: string, year: number): Promise<LeaveBalance[]>;
  calculateAvailableDays(balance: LeaveBalance): number;
  validateSufficientBalance(balance: LeaveBalance, requestedDays: number): ValidationResult;
}

export class LeaveBalanceService implements ILeaveBalanceService {
  constructor(
    private readonly balanceRepository: ILeaveBalanceRepository,
    private readonly auditLogService: AuditLogService
  ) {}

  async getEmployeeBalance(employeeId: string, policyId: string, year: number): Promise<LeaveBalance | null> {
    return this.balanceRepository.findByEmployeeAndPolicyAndYear(employeeId, policyId, year);
  }

  async getEmployeeBalancesForYear(employeeId: string, year: number): Promise<LeaveBalance[]> {
    return this.balanceRepository.findByEmployeeAndYear(employeeId, year);
  }

  calculateAvailableDays(balance: LeaveBalance): number {
    return Number(balance.balanceDays) + Number(balance.accruedDays) - Number(balance.usedDays);
  }

  validateSufficientBalance(balance: LeaveBalance, requestedDays: number): ValidationResult {
    const errors: string[] = [];
    const availableDays = this.calculateAvailableDays(balance);

    if (requestedDays > availableDays) {
      errors.push(`Insufficient balance: requested ${requestedDays} days, available ${availableDays.toFixed(2)} days`);
    }

    return {
      isValid: errors.length === 0,
      errors
    };
  }
